const Redis = require('ioredis');
const redis = new Redis({ host: 'redis', port: 6379 });
const data = $input.first().json;
const respuesta = (data.content || '').trim().toUpperCase();

// Buscar turno pendiente — buscamos en todos los keys tp:pending:*
// Por simplicidad buscamos el más reciente
let pending = null;
let clientChatId = null;
try {
  const keys = await redis.keys('tp:pending:*');
  if (keys.length > 0) {
    // Tomar el más reciente por timestamp
    let newest = null;
    for (const k of keys) {
      const val = await redis.get(k);
      if (val) {
        const p = JSON.parse(val);
        if (!newest || p.timestamp > newest.timestamp) { newest = p; clientChatId = k.replace('tp:pending:', ''); }
      }
    }
    pending = newest;
  }
} finally { await redis.quit(); }

return [{ json: {
  respuesta_roxana: respuesta,
  es_si: respuesta === 'SI' || respuesta.startsWith('SI'),
  es_no: respuesta === 'NO' || respuesta.startsWith('NO'),
  pending,
  client_chat_id: clientChatId,
  instance: data.instance
}}];

