const chatId = $('Cargar Turno Pendiente').first().json.client_chat_id;
try {
  await redis.del('tp:pending:' + chatId);
  await redis.set('tp:state:' + chatId, JSON.stringify({ status: 'confirmed' }), 'EX', 86400);
} finally { await redis.quit(); }
return [{ json: $('Cargar Turno Pendiente').first().json }];

